args.sparql:
SELECT ?award_label WHERE {
  wd:Q103372692 wdt:P166 ?award .
  ?award wdt:P1246 wd:Q109916196 .
  ?award rdfs:label ?award_label .
  FILTER(LANG(?award_label) = 'en')
}

SELECT ?award ?awardLabel WHERE {
  wd:Q103372692 wdt:P166 ?award .
  ?award wdt:P1246 wd:Q109916196 .
  ?award rdfs:label ?awardLabel .
  FILTER(LANG(?awardLabel) = 'en')
}
